
(()=>{function particles(){const c=document.querySelector('.g42-field'); if(!c||c.dataset.ready)return; c.dataset.ready='1'; const ctx=c.getContext('2d'); let w=0,h=0; const dots=Array.from({length:72},(_,i)=>({x:Math.random(),y:Math.random(),v:.16+Math.random()*.55,r:1+Math.random()*2,c:i%3})); function size(){w=c.width=innerWidth*devicePixelRatio;h=c.height=innerHeight*devicePixelRatio} addEventListener('resize',size,{passive:true}); size(); function frame(){ctx.clearRect(0,0,w,h); dots.forEach(d=>{d.y-=d.v/innerHeight;if(d.y<-.05){d.y=1.05;d.x=Math.random()} const x=d.x*w,y=d.y*h; ctx.fillStyle=d.c===0?'rgba(111,255,224,.55)':d.c===1?'rgba(117,221,255,.42)':'rgba(255,241,138,.38)'; ctx.beginPath();ctx.arc(x,y,d.r*devicePixelRatio,0,Math.PI*2);ctx.fill();ctx.strokeStyle='rgba(255,241,138,.12)';ctx.beginPath();ctx.moveTo(x,y+10*devicePixelRatio);ctx.lineTo(x,y+38*devicePixelRatio);ctx.stroke();}); requestAnimationFrame(frame)} frame()} if(document.readyState==='loading')document.addEventListener('DOMContentLoaded',particles);else particles();})();
